def compute_score() -> tuple[str, float]:
    # Use VLM to compare original vs modified slide 2 and detect if a new text box was added
    original_image = None
    modified_image = None

    # Find slide 2 in original screenshots
    for s in original_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 2:
                original_image = s.image_path
                break
        except Exception:
            continue

    # Find slide 2 in modified screenshots
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 2:
                modified_image = s.image_path
                break
        except Exception:
            continue

    if not modified_image:
        return "Modified slide 2 screenshot not found.", 0.0
    if not original_image:
        return "Original slide 2 screenshot not found.", 0.0
    prompt = (
        "Compare these two images of slide 2: the first is the original, the second is the modified.\n"
        "Has a new text box been added in the modified slide that was not present in the original?\n"
        "Ignore minor formatting changes, font/style changes, or small position tweaks in existing boxes;\n"
        "focus only on whether an additional text box appears. Respond YES or NO with a brief justification."
    )

    try:
        response = vlm_call(images=[original_image, modified_image], prompt=prompt, temperature=0.1)
        resp = str(response).strip().lower()
        if resp.startswith('yes'):
            return response, 1.0
        elif resp.startswith('no'):
            return response, 0.0
        else:
            return f"Unclear VLM response: {response}", 0.0
    except Exception as e:
        return f"Error during VLM comparison: {str(e)}", 0.0

