    extraneous = []
    # Check slides added/removed/modified
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        extraneous.append('Slides added or removed')
    # Slide modifications (except for slide 2)
    for orig, mod in ppt_diff.modified_slides:
        if orig.slide_number != 2:
            extraneous.append(f'Slide {orig.slide_number} modified')
    # Any animations or transitions added/removed/modified?
    if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
        extraneous.append('Animations changed')
    if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
        extraneous.append('Transitions changed')
    # Extra shapes added/removed on other slides
    # Can't check shape diffs via ppt_diff, but can check added/removed slides and slide-level mods
    if extraneous:
        return f"Extraneous modifications found: {', '.join(extraneous)}", 0.0
    return "No extraneous modifications detected.", 1.0
